function diffDuration(start, end) {
  const s = new Date(start + 'T00:00:00Z');
  const e = new Date(end + 'T00:00:00Z');
  let y = e.getUTCFullYear() - s.getUTCFullYear();
  let cursor = new Date(Date.UTC(s.getUTCFullYear() + y, s.getUTCMonth(), s.getUTCDate()));
  if (cursor > e) {
    y--;
    cursor = new Date(Date.UTC(s.getUTCFullYear() + y, s.getUTCMonth(), s.getUTCDate()));
  }
  let m = (e.getUTCFullYear() - cursor.getUTCFullYear()) * 12 + (e.getUTCMonth() - cursor.getUTCMonth());
  let cursor2 = new Date(Date.UTC(cursor.getUTCFullYear(), cursor.getUTCMonth() + m, cursor.getUTCDate()));
  if (cursor2 > e) {
    m--;
    cursor2 = new Date(Date.UTC(cursor.getUTCFullYear(), cursor.getUTCMonth() + m, cursor.getUTCDate()));
  }
  const d = Math.round((e - cursor2) / 86400000);
  const total = Math.round((e - s) / 86400000) + 1;
  return { y, m, d, total };
}
console.log('ByteDance', diffDuration('2020-04-08', '2026-05-22'));
console.log('Beijing', diffDuration('2017-12-22', '2026-05-22'));
